import React from 'react'
import { useState, useEffect } from "react";
import PropTypes from 'prop-types'
import navIcon1 from '../assets/img/nav-icon1.svg';
import navIcon2 from '../assets/img/nav-icon2.svg';
import navIcon3 from '../assets/img/nav-icon3.svg';
// import { HashLink } from 'react-router-hash-link';







export default function Navbar(props) {

 const[activeLink,setActiveLink]= useState('home');

 const onUpdateActiveLink=(value)=>{
    setActiveLink(value);
}
  return (
    <>
      <nav className="navbar navbar-expand-lg">
        <a className="navbar-brand mx-3 fw-bold text-white" href="/">{props.title}</a>
        <button className="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarSupportedContent" aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
          <span className="navbar-toggler-icon"></span>
        </button>

        <div className="collapse navbar-collapse custom-navbar" id="navbarSupportedContent">
          <ul className="navbar-nav ms-auto">
            <li className="nav-item active">
              <a  href="#home" className={`nav-link text-white ${activeLink === 'home' ? 'active navbar-link' : 'navbar-link'}`} onClick={()=> onUpdateActiveLink('home')}>Home</a>
            </li>
            <li className="nav-item">
              <a  href="#getintouch" className={`nav-link text-white ${activeLink === 'getintouch' ? 'active navbar-link' : 'navbar-link'}`} onClick={()=> onUpdateActiveLink('getintouch')} >{props.getintouch}</a>
            </li>
            <li className="nav-item">
              <a  href="#about" className={`nav-link text-white ${activeLink === 'about' ? 'active navbar-link' : 'navbar-link'}`} onClick={()=> onUpdateActiveLink('about')}>{props.aboutText}</a>
            </li>        
          </ul>
          <span className="navbar-text">
              <div className="social-icon">
                <a href="#"><img src={navIcon1} alt="" /></a>
                <a href="#"><img src={navIcon2} alt="" /></a>
                <a href="#"><img src={navIcon3} alt="" /></a>
              </div>
              {/* <HashLink to='#connect'>
                <button className="vvd"><span>Let's Connect</span></button>
              </HashLink> */}
            </span>
        </div>
      </nav>
    </>

  )
}

Navbar.prototype={
  title:PropTypes.string.isrequired,
  videos:PropTypes.string.isRequired
}

Navbar.defaultProps={
  title:"Alan.is",
  getintouch:"Get in Touch",
  aboutText:"About me"
};
